---受击对象位移
---
---@class LBattleSkillActHitMove
local LBattleSkillActHitMove = classX("LBattleSkillActHitMove", nil)

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActHitMove.Execute(player,effData, playState)
    local _hitHeros = player:GetHitHeroes()
    if table.isempty(_hitHeros)then
        return
    end

    local _viewMgr = player:GetViewMgr()

    local offset = Vector3.New(effData.effOffsetStart.x,effData.effOffsetStart.y,0)
    local time = effData.playTime
    for k,v in pairs(_hitHeros) do
        local heroId = k
        local obj = _viewMgr:GetUnitView(heroId)
        if obj then
            local tarPos = obj:GetPosition() + offset
            obj:StartMove(tarPos,time)
        end
    end
end

return LBattleSkillActHitMove